# [repr (u8)] # [derive (Copy , Clone , Debug , Eq , PartialEq , Ord , PartialOrd)] # [cfg_attr (feature = "defmt" , derive (defmt :: Format))] pub enum Command { # [doc = "No Operation"] NOP = 0x0 , # [doc = "Normal Descriptor Set and Run"] RUN = 0x01 , _RESERVED_2 = 0x02 , # [doc = "Stop Descriptor"] STOP = 0x03 , } impl Command { # [inline (always)] pub const fn from_bits (val : u8) -> Command { unsafe { core :: mem :: transmute (val & 0x03) } } # [inline (always)] pub const fn to_bits (self) -> u8 { unsafe { core :: mem :: transmute (self) } } } impl From < u8 > for Command { # [inline (always)] fn from (val : u8) -> Command { Command :: from_bits (val) } } impl From < Command > for u8 { # [inline (always)] fn from (val : Command) -> u8 { Command :: to_bits (val) } }